// import React from "react";
import { motion } from "framer-motion";
import { SectionLabel, sectionTitle } from "./Skills";

export default function Contact({ contact }) {
  const items = [
    { icon: "✉", label: "Email", value: contact.email, href: `mailto:${contact.email}` },
    { icon: "📞", label: "Phone", value: contact.phone, href: `tel:${contact.phone}` },
    { icon: "in", label: "LinkedIn", value: contact.linkedin, href: contact.linkedinUrl },
    { icon: "📍", label: "Location", value: contact.location, href: null },
  ];

  /* 🔥 Animations */
  const container = {
    hidden: {},
    show: {
      transition: { staggerChildren: 0.15 },
    },
  };

  const fadeUp = {
    hidden: { opacity: 0, y: 40 },
    show: {
      opacity: 1,
      y: 0,
      transition: { duration: 0.6, ease: "easeOut" },
    },
  };

  const cardAnim = {
    hidden: { opacity: 0, y: 50, scale: 0.95 },
    show: {
      opacity: 1,
      y: 0,
      scale: 1,
      transition: { duration: 0.5 },
    },
  };

  return (
    <>
      <style>{`
        .contact-section {
          padding: clamp(2.5rem, 6vw, 5rem) clamp(1.25rem, 5vw, 4rem);
          text-align: center;
        }

        /* 🔥 Better responsive grid */
        .contact-grid {
          display: grid;
          grid-template-columns: repeat(auto-fit, minmax(160px, 1fr));
          gap: clamp(0.8rem, 2vw, 1.2rem);
          max-width: 900px;
          margin: 0 auto 2rem;
        }

        .contact-card {
          background: var(--surface);
          border: 1px solid var(--border);
          border-radius: var(--radius);
          padding: clamp(0.9rem, 2.5vw, 1.4rem) clamp(0.75rem, 1.5vw, 1rem);
          display: flex;
          flex-direction: column;
          gap: 6px;
          transition: border-color 0.25s ease, transform 0.25s ease, box-shadow 0.25s ease;
          text-decoration: none;
          text-align: left;
          backdrop-filter: blur(10px);
        }

        .contact-card.clickable:hover {
          border-color: var(--accent);
          transform: translateY(-6px) scale(1.03);
          box-shadow: 0 10px 30px rgba(0,0,0,0.2);
        }

        .contact-icon {
          font-size: clamp(1rem, 2vw, 1.3rem);
        }

        .contact-lbl {
          font-size: clamp(0.62rem, 0.9vw, 0.7rem);
          color: var(--muted);
          font-family: var(--font-display);
          font-weight: 700;
          letter-spacing: 0.1em;
          text-transform: uppercase;
        }

        .contact-val {
          font-size: clamp(0.75rem, 1.2vw, 0.9rem);
          color: var(--text);
          font-weight: 500;
          word-break: break-word;
          line-height: 1.4;
        }

        /* 🔥 CTA Button */
        .contact-cta {
          display: inline-flex;
          align-items: center;
          gap: 8px;
          background: linear-gradient(135deg, var(--accent), var(--accent2));
          color: #fff;
          padding: clamp(10px, 2vw, 14px) clamp(24px, 4vw, 36px);
          border-radius: 99px;
          font-family: var(--font-display);
          font-weight: 700;
          font-size: clamp(0.85rem, 1.5vw, 1rem);
          letter-spacing: 0.02em;
          transition: opacity 0.2s, transform 0.2s;
          text-decoration: none;
        }

        .contact-cta:hover {
          opacity: 0.9;
          transform: scale(1.05);
        }

        .footer-txt {
          color: var(--muted);
          font-size: clamp(0.7rem, 1vw, 0.8rem);
          margin-top: 3rem;
        }
      `}</style>

      <section className="contact-section" id="contact">
        <motion.div
          variants={container}
          initial="hidden"
          whileInView="show"
          viewport={{ once: true }}
        >
          <motion.div variants={fadeUp}>
            <SectionLabel text="Contact" />
          </motion.div>

          <motion.h2
            style={{ ...sectionTitle, textAlign: "center" }}
            variants={fadeUp}
          >
            Let's Build Something
          </motion.h2>

          <motion.p
            variants={fadeUp}
            style={{
              color: "var(--muted)",
              marginBottom: "2rem",
              maxWidth: 440,
              margin: "0 auto 2rem",
              fontSize: "clamp(0.85rem, 1.4vw, 0.98rem)",
            }}
          >
            Available for full-time roles and exciting fintech / enterprise projects.
          </motion.p>

          {/* 🔥 Cards */}
          <motion.div className="contact-grid" variants={container}>
            {items.map((item, i) => (
              <motion.a
                key={i}
                href={item.href || undefined}
                target={item.href?.startsWith("http") ? "_blank" : undefined}
                rel="noreferrer"
                className={`contact-card${item.href ? " clickable" : ""}`}
                style={{ color: "inherit" }}
                variants={cardAnim}
                whileHover={{
                  y: -8,
                  scale: 1.05,
                }}
              >
                <span className="contact-icon">{item.icon}</span>
                <span className="contact-lbl">{item.label}</span>
                <span className="contact-val">{item.value}</span>
              </motion.a>
            ))}
          </motion.div>

          {/* 🔥 CTA */}
          <motion.a
            href="mailto:chavanak870@gmail.com"
            className="contact-cta"
            variants={fadeUp}
            whileHover={{ scale: 1.08 }}
            whileTap={{ scale: 0.95 }}
          >
            ✉ Send Email
          </motion.a>

          <motion.div className="footer-txt" variants={fadeUp}>
            Built with React · Designed to impress · © {new Date().getFullYear()} Akash Chavan
          </motion.div>
        </motion.div>
      </section>
    </>
  );
}
